import axios from "axios";
import FixtureList from "../components/fixture/fixture-list";
import SeasonSummary from "../components/season/season-summary";
import TigersFixtures from '../data/fixtures/fixtures'
import { fetchData } from '../services/seasonservice'
import React, { useEffect, useState } from 'react';

const Home = () => {
    const [data, setData] = useState(null);

    useEffect(() => {
        axios.get('http://localhost:5000/api/seasons') // Replace with your API URL
            .then(response => setData(response.data))
            .catch(error => console.error('There was an error!', error));
    }, []);


    return(
        <>
            <h3>Tigers Results</h3>
            <FixtureList fixturesToShow={TigersFixtures}></FixtureList>   
            <SeasonSummary fixtures={TigersFixtures}/>
            <div>
                {   data ? <div>{JSON.stringify(data)}</div> : <p>Loading...</p>}
            </div>
        </>
    )
}
export default Home;
